const now = new Date();
function madridYMD(d){ return d.toLocaleDateString('en-CA', { timeZone:'Europe/Madrid' }); }
function madridDow(d){
  const wd = new Intl.DateTimeFormat('en-US', { timeZone:'Europe/Madrid', weekday:'short' }).format(d);
  return ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].indexOf(wd);
}
function ymdToDate(s){ return new Date(s + 'T00:00:00Z'); }
function ymdFromDate(d){ return d.toISOString().substring(0,10); }
function addDays(s,n){ const d = ymdToDate(s); d.setUTCDate(d.getUTCDate()+n); return ymdFromDate(d); }
const todayYMD     = madridYMD(now);
const daysSinceMon = madridDow(now);
const weekYMD      = addDays(todayYMD, -daysSinceMon);
const lastWeekYMD  = addDays(weekYMD, -7);
const yesterdayYMD = addDays(todayYMD, -1);
const [yy, mm]     = todayYMD.split('-');
const monthYMD     = `${yy}-${mm}-01`;
const agedYMD      = addDays(todayYMD, -5);
return [{ json: {
  today_ymd: todayYMD, yesterday_ymd: yesterdayYMD,
  week_ymd: weekYMD, last_week_ymd: lastWeekYMD,
  month_ymd: monthYMD, aged_ymd: agedYMD,
  now_iso: now.toISOString()
} }];

let acc = $('Guardar Incidencias').first().json || {};
const body = $input.first().json || {};
const metrics = Array.isArray(body.ticket_metrics) ? body.ticket_metrics : [];
const manualResults = (acc.zd_today_manual && acc.zd_today_manual.results) || [];
const ticketsById = new Map();
for (const t of manualResults) { if (t && t.id != null) ticketsById.set(String(t.id), t); }
const todayManualIds = new Set(ticketsById.keys());
const todayMetrics = metrics.filter(m => m && m.ticket_id != null && todayManualIds.has(String(m.ticket_id)));
// Detalle por ticket (los respondidos suman a la media; los pendientes salen aparte).
const answered = [];
const pending  = [];
for (const m of todayMetrics) {
  const t = ticketsById.get(String(m.ticket_id)) || {};
  const mins = m && m.reply_time_in_minutes && m.reply_time_in_minutes.calendar;
  const row = {
    ticket_id: m.ticket_id,
    subject: t.subject || '(sin asunto)',
    created_at: t.created_at || null,
    reply_time_min: typeof mins === 'number' ? mins : null,
    url: `https://soporteyurest.zendesk.com/agent/tickets/${m.ticket_id}`
  };
  if (typeof mins === 'number' && mins > 0) answered.push(row);
  else pending.push(row);
}
answered.sort((a,b) => b.reply_time_min - a.reply_time_min);
const times = answered.map(r => r.reply_time_min);
const sample = times.length;
const avgMin = sample ? Math.round(times.reduce((a,b)=>a+b,0) / sample) : null;
const sorted = times.slice().sort((a,b)=>a-b);
const median = sample ? sorted[Math.floor(sample/2)] : null;
const minV = sample ? sorted[0] : null;
const maxV = sample ? sorted[sorted.length-1] : null;
return [{ json: { ...acc,
  frt_avg_min: avgMin,
  frt_sample: sample,
  frt_answered: sample,
  frt_pending: todayMetrics.length - sample,
  frt_min: minV,
  frt_max: maxV,
  frt_median: median,
  frt_breakdown: answered,
  frt_pending_list: pending
} }];

// Agregar todos los counters en el JSON final (sin histRes-dependent)
const d = $input.first().json;
function count(o){ return (o && (typeof o.count === 'number' ? o.count : (Array.isArray(o.results) ? o.results.length : 0))) || 0; }
function results(o){ return (o && Array.isArray(o.results)) ? o.results : []; }

const today_ia      = count(d.zd_today_ia);
const today_manual  = count(d.zd_today_manual);
const yesterday_ia  = count(d.zd_yesterday_ia);
const yesterday_man = count(d.zd_yesterday_manual);
const week_ia       = count(d.zd_week_ia);
const week_manual   = count(d.zd_week_manual);
const month_ia      = count(d.zd_month_ia);
const month_manual  = count(d.zd_month_manual);
const open          = count(d.zd_open);
const solved_today  = count(d.zd_solved_today);
const aged          = count(d.zd_aged);
const incidencias   = count(d.zd_incidencias);

// Incidencias buckets desde results (HTTP search devuelve hasta 100)
const incRes = results(d.zd_incidencias);
const incidencias_list = incRes.map(t => ({
  id: t.id,
  subject: t.subject || '(sin asunto)',
  status: t.status,
  priority: t.priority,
  created_at: t.created_at,
  organization_id: t.organization_id,
  age_days: t.created_at ? Math.floor((Date.now() - new Date(t.created_at).getTime()) / 86400000) : null,
  url: `https://soporteyurest.zendesk.com/agent/tickets/${t.id}`
}));
const incidencias_buckets = { lt30:0, b30_60:0, b60_100:0, gt100:0 };
for (const t of incidencias_list) {
  const a = t.age_days || 0;
  if (a < 30) incidencias_buckets.lt30++;
  else if (a < 60) incidencias_buckets.b30_60++;
  else if (a < 100) incidencias_buckets.b60_100++;
  else incidencias_buckets.gt100++;
}

// Aged list (puede traer hasta 100 — la HTTP search no pagina)
const agedRes = results(d.zd_aged);
const aged_tickets_list = agedRes
  .filter(t => t && t.id)
  .sort((a,b) => new Date(a.created_at) - new Date(b.created_at))
  .map(t => ({
    id: t.id,
    subject: t.subject || '(sin asunto)',
    status: t.status,
    priority: t.priority,
    created_at: t.created_at,
    organization_id: t.organization_id,
    age_days: t.created_at ? Math.floor((Date.now() - new Date(t.created_at).getTime()) / 86400000) : null,
    url: `https://soporteyurest.zendesk.com/agent/tickets/${t.id}`
  }));

return [{ json: {
  generated_at: new Date().toISOString(),
  _workflow_version: 'light-v1',
  _light: true,
  // Tickets counters
  tickets_today: today_ia + today_manual,
  tickets_today_ia: today_ia,
  tickets_today_manual: today_manual,
  tickets_yesterday: yesterday_ia + yesterday_man,
  tickets_yesterday_ia: yesterday_ia,
  tickets_yesterday_manual: yesterday_man,
  tickets_week: week_ia + week_manual,
  tickets_week_ia: week_ia,
  tickets_week_manual: week_manual,
  tickets_month: month_ia + month_manual,
  tickets_month_ia: month_ia,
  tickets_month_manual: month_manual,
  tickets_open: open,
  tickets_solved_today: solved_today,
  backlog_today: today_manual - solved_today,
  // Operativos
  tickets_aged_3d: aged,
  tickets_incidencias_dev: incidencias,
  aged_tickets_list,
  incidencias_list,
  incidencias_buckets,
  // FRT
  frt_avg_min: d.frt_avg_min ?? null,
  frt_sample: d.frt_sample ?? 0,
  frt_answered: d.frt_answered ?? 0,
  frt_pending: d.frt_pending ?? 0,
  frt_min: d.frt_min ?? null,
  frt_max: d.frt_max ?? null,
  frt_median: d.frt_median ?? null,
  frt_breakdown: d.frt_breakdown || [],
  frt_pending_list: d.frt_pending_list || []
} }];
